    90→func (r *gitRepository) GetDefaultBranch(ctx context.Context) (string, error) {
    91→	ctx, _ = r.withGitContext(ctx, "")
    92→
    93→	// Get all refs to find the default branch
    94→	refs, err := r.client.ListRefs(ctx)
    95→	if err != nil {
    96→		return "", fmt.Errorf("list refs: %w", err)
    97→	}
    98→
    99→	var hasMain, hasMaster bool
   100→	var firstBranch string
   101→
   102→	// Single pass through refs to find main, master, or first branch alphabetically
   103→	for _, ref := range refs {
   104→		if !strings.HasPrefix(ref.Name, "refs/heads/") {
   105→			continue
   106→		}
   107→
   108→		branchName := strings.TrimPrefix(ref.Name, "refs/heads/")
   109→
   110→		// Check for main or master
   111→		switch branchName {
   112→		case "main":
   113→			hasMain = true
   114→		case "master":
   115→			hasMaster = true
   116→		}
   117→
   118→		// Track first branch alphabetically as fallback
   119→		if firstBranch == "" || branchName < firstBranch {
   120→			firstBranch = branchName
   121→		}
   122→	}
   123→
   124→	// No branches found
   125→	if firstBranch == "" {
   126→		return "", fmt.Errorf("no branches found in repository")
   127→	}
   128→
   129→	// Prefer main, then master, then first branch alphabetically
   130→	if hasMain {
   131→		return "main", nil
   132→	}
   133→	if hasMaster {
   134→		return "master", nil
   135→	}
   136→
   137→	// If neither main nor master exists, return the first branch alphabetically.
   138→	// This provides deterministic behavior when working with repositories that use
   139→	// non-standard default branch names (e.g., "develop", "trunk", custom names).
   140→	// Users can always change the branch afterward or specify it directly in the repository configuration.
   141→	return firstBranch, nil
   142→}
