   337→func (r *gitRepository) ReadTree(ctx context.Context, ref string) ([]repository.FileTreeEntry, error) {
   338→	ctx, _ = r.withGitContext(ctx, ref)
   339→
   340→	// Resolve ref to commit hash
   341→	refHash, err := r.resolveRefToHash(ctx, ref)
   342→	if err != nil {
   343→		return nil, err
   344→	}
   345→
   346→	// Get flat tree using nanogit's GetFlatTree
   347→	tree, err := r.client.GetFlatTree(ctx, refHash)
   348→	if err != nil {
   349→		if errors.Is(err, nanogit.ErrObjectNotFound) {
   350→			return nil, repository.ErrRefNotFound
   351→		}
   352→		return nil, fmt.Errorf("get flat tree: %w", mapNanogitError(err))
   353→	}
   354→
   355→	entries := make([]repository.FileTreeEntry, 0, len(tree.Entries))
   356→	for _, entry := range tree.Entries {
   357→		isBlob := entry.Type == protocol.ObjectTypeBlob
   358→		// Apply path prefix filtering
   359→		relativePath, err := safepath.RelativeTo(entry.Path, r.gitConfig.Path)
   360→		if err != nil {
   361→			// File is outside configured path, skip it
   362→			continue
   363→		}
   364→
   365→		filePath := relativePath
   366→		if !isBlob && !safepath.IsDir(filePath) {
   367→			filePath = filePath + "/"
   368→		}
   369→
   370→		converted := repository.FileTreeEntry{
   371→			Path: filePath,
   372→			// TODO: Remove size from repository.FileTreeEntry. We don't need it per se.
   373→			Size: 0, // FlatTreeEntry doesn't have size, set to 0
   374→			Hash: entry.Hash.String(),
   375→			Blob: isBlob,
   376→		}
   377→		entries = append(entries, converted)
   378→	}
   379→	return entries, nil
   380→}
