   473→func (r *gitRepository) Write(ctx context.Context, path string, ref string, data []byte, message string) error {
   474→	if ref == "" {
   475→		ref = r.gitConfig.Branch
   476→	}
   477→
   478→	ctx, _ = r.withGitContext(ctx, ref)
   479→	info, err := r.Read(ctx, path, ref)
   480→	if err != nil && !(errors.Is(err, repository.ErrFileNotFound)) {
   481→		return fmt.Errorf("check if file exists before writing: %w", err)
   482→	}
   483→	if err == nil {
   484→		// If the value already exists and is the same, we don't need to do anything
   485→		if bytes.Equal(info.Data, data) {
   486→			return nil
   487→		}
   488→		return r.Update(ctx, path, ref, data, message)
   489→	}
   490→
   491→	return r.Create(ctx, path, ref, data, message)
