   541→func (r *gitRepository) delete(ctx context.Context, path string, writer nanogit.StagedWriter) error {
   542→	finalPath := safepath.Join(r.gitConfig.Path, path)
   543→	// Check if it's a directory - use DeleteTree for directories, DeleteBlob for files
   544→	if safepath.IsDir(path) {
   545→		trimmed := strings.TrimSuffix(finalPath, "/")
   546→		if _, err := writer.DeleteTree(ctx, trimmed); err != nil {
   547→			if errors.Is(err, nanogit.ErrObjectNotFound) {
   548→				return repository.ErrFileNotFound
   549→			}
   550→			return fmt.Errorf("delete tree: %w", mapNanogitError(err))
   551→		}
   552→	} else {
   553→		if _, err := writer.DeleteBlob(ctx, finalPath); err != nil {
   554→			if errors.Is(err, nanogit.ErrObjectNotFound) {
   555→				return repository.ErrFileNotFound
   556→			}
   557→			return fmt.Errorf("delete blob: %w", mapNanogitError(err))
   558→		}
   559→	}
   560→
   561→	return nil
   562→}
