   564→func (r *gitRepository) move(ctx context.Context, oldPath, newPath string, writer nanogit.StagedWriter) error {
   565→	oldFinalPath := safepath.Join(r.gitConfig.Path, oldPath)
   566→	newFinalPath := safepath.Join(r.gitConfig.Path, newPath)
   567→
   568→	// Check if moving directories
   569→	if safepath.IsDir(oldPath) && safepath.IsDir(newPath) {
   570→		// For directories, trim trailing slashes and use MoveTree
   571→		oldTrimmed := strings.TrimSuffix(oldFinalPath, "/")
   572→		newTrimmed := strings.TrimSuffix(newFinalPath, "/")
   573→
   574→		if _, err := writer.MoveTree(ctx, oldTrimmed, newTrimmed); err != nil {
   575→			if errors.Is(err, nanogit.ErrObjectNotFound) {
   576→				return repository.ErrFileNotFound
   577→			}
   578→			if errors.Is(err, nanogit.ErrObjectAlreadyExists) {
   579→				return repository.ErrFileAlreadyExists
   580→			}
   581→			return fmt.Errorf("move tree: %w", mapNanogitError(err))
   582→		}
   583→	} else if !safepath.IsDir(oldPath) && !safepath.IsDir(newPath) {
   584→		// For files, use MoveBlob operation
   585→		if _, err := writer.MoveBlob(ctx, oldFinalPath, newFinalPath); err != nil {
   586→			if errors.Is(err, nanogit.ErrObjectNotFound) {
   587→				return repository.ErrFileNotFound
   588→			}
   589→			if errors.Is(err, nanogit.ErrObjectAlreadyExists) {
   590→				return repository.ErrFileAlreadyExists
   591→			}
   592→			return fmt.Errorf("move blob: %w", mapNanogitError(err))
   593→		}
   594→	} else {
   595→		// Mismatched types (file to directory or vice versa)
   596→		return apierrors.NewBadRequest("cannot move between file and directory types")
   597→	}
   598→
   599→	return nil
   600→}
