   744→// resolveRefToHash resolves a ref (branch name or commit hash) to a commit hash
   745→func (r *gitRepository) resolveRefToHash(ctx context.Context, ref string) (hash.Hash, error) {
   746→	ctx, _ = r.withGitContext(ctx, ref)
   747→
   748→	// Use default branch if ref is empty
   749→	if ref == "" {
   750→		ref = r.gitConfig.Branch
   751→	}
   752→
   753→	// Try to parse ref as a hash first
   754→	refHash, err := hash.FromHex(ref)
   755→	if err == nil && refHash != hash.Zero {
   756→		// Valid hash, return it
   757→		return refHash, nil
   758→	}
   759→
   760→	// Prefix ref with refs/heads/
   761→	ref = fmt.Sprintf("refs/heads/%s", ref)
   762→
   763→	// Not a valid hash, try to resolve as a branch reference
   764→	branchRef, err := r.client.GetRef(ctx, ref)
   765→	if err != nil {
   766→		if errors.Is(err, nanogit.ErrObjectNotFound) {
   767→			return hash.Zero, fmt.Errorf("ref not found: %s: %w", ref, repository.ErrRefNotFound)
   768→		}
   769→		return hash.Zero, fmt.Errorf("get ref %s: %w", ref, mapNanogitError(err))
   770→	}
   771→
   772→	return branchRef.Hash, nil
   773→}
   774→
   775→// ensureBranchExists checks if a branch exists and creates it if it doesn't,
   776→// returning the branch reference to avoid duplicate GetRef calls
   777→func (r *gitRepository) ensureBranchExists(ctx context.Context, branchName string) (nanogit.Ref, error) {
   778→	ctx, _ = r.withGitContext(ctx, branchName)
   779→
   780→	if !IsValidGitBranchName(branchName) {
   781→		return nanogit.Ref{}, &apierrors.StatusError{
   782→			ErrStatus: metav1.Status{
   783→				Code:    http.StatusBadRequest,
   784→				Message: "invalid branch name",
   785→			},
   786→		}
   787→	}
   788→
   789→	// Check if branch exists by trying to get the branch reference
   790→	branchRef, err := r.client.GetRef(ctx, fmt.Sprintf("refs/heads/%s", branchName))
   791→	if err == nil {
   792→		// Branch exists, return it
   793→		logging.FromContext(ctx).Info("branch already exists", "branch", branchName)
   794→		return branchRef, nil
   795→	}
   796→
   797→	// If error is not "ref not found", return the error
   798→	if !errors.Is(err, nanogit.ErrObjectNotFound) {
   799→		return nanogit.Ref{}, fmt.Errorf("check branch exists: %w", err)
   800→	}
   801→
   802→	// Branch doesn't exist, create it based on the configured branch
   803→	srcBranch := r.gitConfig.Branch
   804→	srcRef, err := r.client.GetRef(ctx, fmt.Sprintf("refs/heads/%s", srcBranch))
   805→	if err != nil {
   806→		return nanogit.Ref{}, fmt.Errorf("get source branch ref: %w", err)
   807→	}
   808→
   809→	// Create the new branch reference
   810→	newRef := nanogit.Ref{
   811→		Name: fmt.Sprintf("refs/heads/%s", branchName),
   812→		Hash: srcRef.Hash,
   813→	}
   814→
   815→	if err := r.client.CreateRef(ctx, newRef); err != nil {
   816→		return nanogit.Ref{}, fmt.Errorf("create branch: %w", err)
   817→	}
   818→
   819→	return newRef, nil
   820→}
