   822→// createSignature creates author and committer signatures using the context signature if available,
   823→// falling back to default Grafana signature
   824→func (r *gitRepository) createSignature(ctx context.Context) (nanogit.Author, nanogit.Committer) {
   825→	author := nanogit.Author{
   826→		Name:  "Grafana",
   827→		Email: "noreply@grafana.com",
   828→		Time:  time.Now(),
   829→	}
   830→
   831→	// Use signature from context if available
   832→	if sig := repository.GetAuthorSignature(ctx); sig != nil {
   833→		if sig.Name != "" {
   834→			author.Name = sig.Name
   835→		}
   836→		if sig.Email != "" {
   837→			author.Email = sig.Email
   838→		}
   839→		if !sig.When.IsZero() {
   840→			author.Time = sig.When
   841→		}
   842→	}
   843→
   844→	if author.Time.IsZero() {
   845→		author.Time = time.Now()
   846→	}
   847→
   848→	// Author and committer are always the same (for now)
   849→	return author, nanogit.Committer(author)
   850→}
