   852→func (r *gitRepository) commit(ctx context.Context, writer nanogit.StagedWriter, comment string) error {
   853→	author, committer := r.createSignature(ctx)
   854→	if _, err := writer.Commit(ctx, comment, author, committer); err != nil {
   855→		if errors.Is(err, nanogit.ErrNothingToCommit) {
   856→			return repository.ErrNothingToCommit
   857→		}
   858→
   859→		return fmt.Errorf("commit changes: %w", err)
   860→	}
   861→	return nil
   862→}
