   864→func (r *gitRepository) commitAndPush(ctx context.Context, writer nanogit.StagedWriter, comment string) error {
   865→	if err := r.commit(ctx, writer, comment); err != nil {
   866→		return err
   867→	}
   868→
   869→	if err := writer.Push(ctx); err != nil {
   870→		return fmt.Errorf("push changes: %w", mapNanogitError(err))
   871→	}
   872→
   873→	return nil
   874→}
